preflight.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  sudo apt-get update
  sudo apt-get install -y build-essential curl file libayatana-appindicator3-dev librsvg2-dev libssl-dev libwebkit2gtk-4.1-dev ffmpeg cmake patchelf wget xdg-utils
  rustup target add x86_64-unknown-linux-gnu
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "windows") {
  choco install ffmpeg -y --no-progress
  rustup target add x86_64-pc-windows-msvc
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "macos") {
  & brew list ffmpeg *> $null
  if ($LASTEXITCODE -ne 0) {
    & brew install ffmpeg
  }
  if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") {
    rustup target add aarch64-apple-darwin
  } else {
    rustup target add x86_64-apple-darwin
  }
}

build.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$platform = switch ($env:SDKWORK_PACKAGE_PLATFORM) {
  "windows" { "windows-x86_64" }
  "linux" { "linux-x86_64" }
  "macos" {
    if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "macos-aarch64" } else { "macos-x86_64" }
  }
  default { throw "Unsupported AutoCut release platform: $env:SDKWORK_PACKAGE_PLATFORM" }
}
pnpm prepare:release-sidecars -- --platform $platform --accept-license

$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "windows") {
  pnpm tauri:build
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  pnpm tauri:build --target x86_64-unknown-linux-gnu
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "macos") {
  $rustTarget = if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "aarch64-apple-darwin" } else { "x86_64-apple-darwin" }
  $appArch = if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "aarch64" } else { "x64" }
  pnpm tauri:build --target $rustTarget
  $appBundle = "packages/sdkwork-autocut-desktop/src-tauri/target/$rustTarget/release/bundle/macos/SDKWork Video Cut.app"
  if (-not (Test-Path -LiteralPath $appBundle -PathType Container)) {
    throw "missing macOS app bundle: $appBundle"
  }
  $bundleDir = Split-Path -Parent $appBundle
  Remove-Item -LiteralPath (Join-Path $bundleDir "*.app.tar.gz") -Force -ErrorAction SilentlyContinue
  $appArchive = Join-Path $bundleDir "SDKWork Video Cut_$($env:SDKWORK_PACKAGE_VERSION)_$appArch.app.tar.gz"
  tar -C $bundleDir -czf $appArchive (Split-Path -Leaf $appBundle)
  if (-not (Test-Path -LiteralPath $appArchive -PathType Leaf)) {
    throw "missing macOS app archive: $appArchive"
  }
} else {
  throw "Unsupported AutoCut release platform: $env:SDKWORK_PACKAGE_PLATFORM"
}

sign.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$platform = switch ($env:SDKWORK_PACKAGE_PLATFORM) {
  "windows" { "windows-x86_64" }
  "linux" { "linux-x86_64" }
  "macos" {
    if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "macos-aarch64" } else { "macos-x86_64" }
  }
  default { throw "Unsupported AutoCut release platform: $env:SDKWORK_PACKAGE_PLATFORM" }
}
pnpm release:installer-signature -- --platform $platform

validate.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$platform = switch ($env:SDKWORK_PACKAGE_PLATFORM) {
  "windows" { "windows-x86_64" }
  "linux" { "linux-x86_64" }
  "macos" {
    if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "macos-aarch64" } else { "macos-x86_64" }
  }
  default { throw "Unsupported AutoCut release platform: $env:SDKWORK_PACKAGE_PLATFORM" }
}
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "windows") {
  $env:SDKWORK_AUTOCUT_RUN_REAL_LLM_SECRET_SMOKE = "true"
}
pnpm release:smoke-preflight -- --platform $platform --require-bundled
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "windows") {
  pnpm release:native-smoke -- --run-real-llm-secret-smoke
} else {
  pnpm release:native-smoke
}
pnpm release:smart-slice-sample -- --platform $platform
pnpm release:evidence -- --platform $platform --output "artifacts/release/autocut-release-evidence-$platform.json"
$expectedEvidence = "artifacts/release/autocut-release-evidence-$platform.json"
if (-not (Test-Path -LiteralPath $expectedEvidence -PathType Leaf)) {
  throw "missing release evidence artifact: $expectedEvidence"
}
